#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int countPrimes(int L, int R) {
        vector<bool> sieve(R + 1, true);
        sieve[0] = sieve[1] = false;
        for (int current_prime = 2; current_prime * current_prime <= R; current_prime++) {
            if (sieve[current_prime]) {
                for (int multiple = current_prime * 2; multiple <= R; multiple += current_prime) {
                    sieve[multiple] = false;
                }
            }
        }
        return count_if(sieve.begin() + L, sieve.begin() + R + 1, [](bool x){ return x; });
    }
};

